define({"topics":[{"title":"DEGOV Woodward Diesel Governor","shortdesc":"<p class=\"shortdesc\">Description of the DEGOV Woodward Diesel Governor in Schematic Editor, which is             used as a standard model for diesel engine governors.<\/p>","href":"t-ug002\/References\/degov_woodward.html","attributes":{"data-id":"doc"},"menu":{"hasChildren":false},"tocID":"doc-d16877e5567","topics":[]},{"title":"IEEE AC1A Exciter","shortdesc":"<p class=\"shortdesc\">Description of the IEEE AC1A Exciter component in Schematic Editor, which represents         the field-controlled alternator-rectifier excitation systems designated Type         AC1A.<\/p>","href":"t-ug002\/References\/ieee_ac1a_exciter.html","attributes":{"data-id":"doc"},"menu":{"hasChildren":false},"tocID":"doc-d16877e5578","topics":[]},{"title":"IEEE AC8B Exciter","shortdesc":"<p class=\"shortdesc\">Description of the IEEE AC8B Exciter component in Schematic Editor, which provides an         excitation system for a synchronous machine and regulates its terminal voltage in generating         mode.<\/p>","href":"t-ug002\/References\/ieee_ac8b_exciter.html","attributes":{"data-id":"doc"},"menu":{"hasChildren":false},"tocID":"doc-d16877e5589","topics":[]},{"title":"IEEE DC1A Exciter","shortdesc":"<p class=\"shortdesc\">Description of the IEEE DC1A Exciter component in Schematic Editor, which provides         generic excitation for a synchronous machine and regulates its terminal voltage in         generating mode.<\/p>","href":"t-ug002\/References\/ieee_dc1a_exciter.html","attributes":{"data-id":"doc"},"menu":{"hasChildren":false},"tocID":"doc-d16877e5600","topics":[]},{"title":"IEEE DC4B Exciter","shortdesc":"<p class=\"shortdesc\">Description of the IEEE DC4B Exciter component in Schematic Editor, which provides         generic excitation for a synchronous machine and regulates its terminal voltage in         generating mode.<\/p>","href":"t-ug002\/References\/ieee_dc4b_exciter.html","attributes":{"data-id":"doc"},"menu":{"hasChildren":false},"tocID":"doc-d16877e5611","topics":[]},{"title":"IEEE ST1A Exciter","shortdesc":"<p class=\"shortdesc\">Description of the IEEE ST1A Exciter component in Schematic Editor, which represents         systems in which the excitation power is supplied through a transformer from the generator         terminals and is regulated by a controlled rectifier.<\/p>","href":"t-ug002\/References\/ieee_st1a_exciter.html","attributes":{"data-id":"doc"},"menu":{"hasChildren":false},"tocID":"doc-d16877e5622","topics":[]},{"title":"IEEE Type 1 Exciter","shortdesc":"<p class=\"shortdesc\">Description of the IEEE Type 1 Exciter component in Schematic Editor, which             provides generic excitation for any synchronous machine and regulates its terminal             voltage in generating mode.<\/p>","href":"t-ug002\/References\/ieee_type1_exciter.html","attributes":{"data-id":"doc"},"menu":{"hasChildren":false},"tocID":"doc-d16877e5633","topics":[]},{"title":"IEEE G1 Governor Valve","shortdesc":"<p class=\"shortdesc\">Description of the IEEE G1 Governor Valve component in Schematic Editor, which         provides what is commonly referred to as the Primary Control or Frequency Response of a         Steam governor-turbine model.<\/p>","href":"t-ug002\/References\/ieee_governor_valve.html","attributes":{"data-id":"doc"},"menu":{"hasChildren":false},"tocID":"doc-d16877e5644","topics":[]},{"title":"IEEE G1 Steam Turbine","shortdesc":"<p class=\"shortdesc\">Description of the IEEE G1 Steam Turbine component in Schematic Editor, a four-stage         cross-compound steam turbine model.<\/p>","href":"t-ug002\/References\/ieee_steam_turbine.html","attributes":{"data-id":"doc"},"menu":{"hasChildren":false},"tocID":"doc-d16877e5655","topics":[]},{"title":"Wind Turbine","shortdesc":"<p class=\"shortdesc\">Description of the Wind Turbine model component in Schematic Editor, which emulates     the mechanical and aerodynamic behavior of a wind turbine.<\/p>","href":"t-ug002\/References\/wind_turbine.html","attributes":{"data-id":"doc"},"menu":{"hasChildren":false},"tocID":"doc-d16877e5666","topics":[]}]});